class Solution:
    def specialTriplets(self, nums):
        MOD = 10**9 + 7
        n = len(nums)
        cnt = 0
        for j in range(n):
            t = nums[j] * 2
            left = 0
            for i in range(j):
                if nums[i] == t:
                    left += 1
            right = 0
            for k in range(j + 1, n):
                if nums[k] == t:
                    right += 1
            cnt = (cnt + left * right) % MOD
        return cnt

