var specialTriplets = function(nums) {
    const MOD = 1000000007n;
    const left = new Map();
    const right = new Map();
    for (const v of nums) right.set(v, (right.get(v) || 0) + 1);
    let ans = 0n;
    for (const v of nums) {
        right.set(v, right.get(v) - 1);
        const t = v * 2;
        const l = BigInt(left.get(t) || 0);
        const r = BigInt(right.get(t) || 0);
        ans = (ans + l * r) % MOD;
        left.set(v, (left.get(v) || 0) + 1);
    }
    return Number(ans);
};
